SELECT * FROM sys_meta_publish
WHERE 1=1

    AND table_code = #{tableCode}


    AND status = #{status}


    AND publish_by = #{publishBy}


    AND publish_time >= #{beginTime}


    AND publish_time <= #{endTime}

ORDER BY id DESC

SELECT * FROM sys_meta_publish
WHERE publish_code = #{publishCode}
LIMIT 1
